swayidle -w timeout 180 'playerctl status 2>/dev/null | grep -q Playing || brightnessctl -s set 5%' timeout 240 'playerctl status 2>/dev/null | grep -q Playing || echo 1 > ~/.cache/qs/lock' timeout 300 'playerctl status 2>/dev/null | grep -q Playing || wlr-randr --output eDP-1 --off' resume 'wlr-randr --output eDP-1 --on; sleep 0.5; brightnessctl -r' before-sleep 'echo 1 > ~/.cache/qs/lock'